#include <bits/stdc++.h>
using namespace std;
const int N=2e6+6;
int n,a[N],q[N],l,r,ans;
int main(){
	scanf("%d",&n);
	for(int i=n/2+1;i<=n/2+n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<=n/2;i++)
		a[i]=a[i+n];
	for(int i=n+1;i<=n+n/2*2;i++)
		a[i]=a[i-n];
	l=1,r=0;
	for(int i=2;i<=n+n/2;i++){
		while(l<=r && q[l]<i-n/2)
			l++;
		while(l<=r && a[q[r]]+i-q[r]<=a[i-1]+1)
			r--;
		q[++r]=i-1;
		ans=max(ans,a[q[l]]+a[i]+i-q[l]);
	}
	l=1,r=0;
	for(int i=n+n/2*2-1;i>n/2;i--){
		while(l<=r && q[l]>i+n/2)
			l++;
		while(l<=r && a[q[r]]+q[r]-i<=a[i+1]+1)
			r--;
		q[++r]=i+1;
		ans=max(ans,a[q[l]]+a[i]+q[l]-i);
	}
	printf("%d",ans);
	return 0;
}
